import math

def _gcd(a, b):
    return math.gcd(a, b)

def _is_prime(n):
    if n < 2:
        return False
    if n == 2 or n == 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def _get_primes(limit):
    primes = []
    is_prime = [True] * (limit + 1)
    if limit >= 0: is_prime[0] = False
    if limit >= 1: is_prime[1] = False
    for p in range(2, limit + 1):
        if is_prime[p]:
            primes.append(p)
            for multiple in range(p * p, limit + 1, p):
                is_prime[multiple] = False
    return primes

def _legendre_symbol(a, p):
    if p < 2 or not _is_prime(p):
        raise ValueError("p must be a prime number")

    a %= p
    if a == 0:
        return 0 

    res = pow(a, (p - 1) // 2, p)
    if res == p - 1:
        return -1
    return res

def _factorize_smooth(n, factor_base):
    exponents = [0] * len(factor_base)

    if n == 0: 
        return None

    if n < 0:
        exponents[0] = 1 
        n = -n

    for i in range(1, len(factor_base)):
        p = factor_base[i]
        while n % p == 0:
            exponents[i] += 1
            n //= p

    if n == 1: 
        return exponents
    else: 
        return None

def _gaussian_elimination_mod2(matrix):
    num_rows = len(matrix)
    if num_rows == 0:
        return []
    num_cols = len(matrix[0])

    augmented_matrix = []
    for i in range(num_rows):
        row = list(matrix[i]) 
        identity_row = [0] * num_rows
        identity_row[i] = 1
        augmented_matrix.append(row + identity_row)

    pivot_row = 0
    pivot_col = 0

    while pivot_row < num_rows and pivot_col < num_cols:
        i_pivot = pivot_row
        while i_pivot < num_rows and augmented_matrix[i_pivot][pivot_col] == 0:
            i_pivot += 1

        if i_pivot < num_rows:
            augmented_matrix[pivot_row], augmented_matrix[i_pivot] = \
                augmented_matrix[i_pivot], augmented_matrix[pivot_row]

            for r in range(num_rows):
                if r != pivot_row and augmented_matrix[r][pivot_col] == 1:
                    for c in range(pivot_col, len(augmented_matrix[0])):
                        augmented_matrix[r][c] = (augmented_matrix[r][c] + augmented_matrix[pivot_row][c]) % 2
            pivot_row += 1
        pivot_col += 1

    null_space_vectors = []
    for r in range(num_rows):
        is_zero_row = True
        for c in range(num_cols):
            if augmented_matrix[r][c] != 0:
                is_zero_row = False
                break
        if is_zero_row:
            null_space_vectors.append(augmented_matrix[r][num_cols:])

    return null_space_vectors


def quadratic_sieve(N):
    if N <= 1:
        return None

    if N % 2 == 0: 
        return 2

    small_primes_limit = min(100, int(math.sqrt(N)) + 1) 
    small_primes = _get_primes(small_primes_limit)
    for p in small_primes:
        if N % p == 0:
            return p

    if _is_prime(N): 
        return None

    B = 25 

    factor_base = [-1] 

    all_primes_up_to_B = _get_primes(B)
    for p in all_primes_up_to_B:
        if p == 2: 
            factor_base.append(p)
        else:
            if _legendre_symbol(N, p) == 1:
                factor_base.append(p)

    num_factor_base_elems = len(factor_base)

    sqrt_N = int(math.sqrt(N))
    relations = [] 

    target_relations_count = num_factor_base_elems + 5 

    x_val = sqrt_N 
    max_x_iterations = min(N // 2, 5000) 

    while True:
        x_val += 1

        if x_val - sqrt_N > max_x_iterations:
            break

        Q_x = x_val * x_val - N

        original_exponents = _factorize_smooth(Q_x, factor_base)

        if original_exponents is not None:
            relations.append((x_val, Q_x, original_exponents))

            if len(relations) >= target_relations_count:
                matrix_mod2 = [[e % 2 for e in r[2]] for r in relations]

                null_space_vectors = _gaussian_elimination_mod2(matrix_mod2)

                for dependency_vector in null_space_vectors:
                    if sum(dependency_vector) == 0: 
                        continue

                    X_val = 1
                    Y_prime_exponents_sum = [0] * num_factor_base_elems

                    for i, include in enumerate(dependency_vector):
                        if include == 1:
                            x_i, _, original_exponents_i = relations[i]
                            X_val = (X_val * x_i) % N
                            for j in range(num_factor_base_elems):
                                Y_prime_exponents_sum[j] += original_exponents_i[j]

                    Y_val = 1
                    is_valid_dependency = True
                    for j in range(num_factor_base_elems):
                        p = factor_base[j]
                        exponent_sum = Y_prime_exponents_sum[j]

                        if exponent_sum % 2 != 0: 
                            is_valid_dependency = False
                            break
                        Y_val = (Y_val * pow(p, exponent_sum // 2, N)) % N

                    if not is_valid_dependency:
                        continue

                    if X_val != Y_val and X_val != (N - Y_val) % N:
                        factor = _gcd(X_val - Y_val, N)
                        if factor != 1 and factor != N:
                            return factor

    return None
